paint.setShader(Skia.Shader.MakeLinearGradient({ x: 0, y: 0 }, { x: width, y: height }, borderColors, [0, 1], 0));
canvas.drawRect({ x: 20 * scale, y: 20 * scale, width: width - 40 * scale, height: height - 40 * scale }, paint);
paint.setShader(null);
paint.setStyle(0);

// 3. Top Banner "SMOKED DAILY"
paint.setColor(Skia.Color('#DC2626'));
canvas.drawRect({ x: width / 2 - 150 * scale, y: 40 * scale, width: 300 * scale, height: 55 * scale }, paint);

paint.setColor(Skia.Color('white'));
const bannerFont = oswald;
bannerFont.setSize(26 * scale);
drawTextCentered(canvas, "SMOKED DAILY", 78 * scale, bannerFont, paint, width);

// 4. Central Brand Name (overlay with semi-transparent charcoal backplate for readability)
paint.setColor(Skia.Color('rgba(28, 25, 23, 0.65)'));
canvas.drawRRect(
  Skia.RRectXY(
    {
      x: 40 * scale,
      y: height / 2 - 70 * scale,
      width: width - 80 * scale,
      height: 140 * scale
    },
    20 * scale,
    20 * scale
  ),
  paint
);

paint.setColor(Skia.Color('#F97316')); // Orange 500
const titleFont = righteous;
titleFont.setSize(65 * scale);
drawTextCentered(canvas, name.toUpperCase(), height / 2 + 15 * scale, titleFont, paint, width);

// 5. Slogan (inside bottom area)
paint.setColor(Skia.Color('#F5F5F4')); // Stone 100
const sloganFont = montserrat;
sloganFont.setSize(22 * scale);
if (slogan) drawTextCentered(canvas, slogan, height - 300 * scale, sloganFont, paint, width);

// Gold/Flame Divider
paint.setColor(Skia.Color('#EA580C'));
canvas.drawRect({ x: width * 0.35, y: height - 260 * scale, width: width * 0.3, height: 3 * scale }, paint);

// 6. Bottom info container (translucent charcoal)
paint.setColor(Skia.Color('rgba(255, 255, 255, 0.08)'));
canvas.drawRRect(
  Skia.RRectXY(
    {
      x: 40 * scale,
      y: height - 220 * scale,
      width: width - 80 * scale,
      height: 150 * scale
    },
    20 * scale,
    20 * scale
  ),
  paint
);

const infoFont = montserrat;
infoFont.setSize(22 * scale);

// Phone
paint.setColor(Skia.Color('#EA580C'));
drawIcon(canvas, 'call', 70 * scale, height - 190 * scale, 28 * scale, paint, icons);
paint.setColor(Skia.Color('white'));
drawTextLeft(canvas, phone, 115 * scale, height - 166 * scale, infoFont, paint, width - 110 * scale - 40 * scale);

// Address
paint.setColor(Skia.Color('#EA580C'));
drawIcon(canvas, 'location', 70 * scale, height - 140 * scale, 28 * scale, paint, icons);
paint.setColor(Skia.Color('white'));
drawTextLeft(canvas, address || '', 115 * scale, height - 116 * scale, infoFont, paint, width - 110 * scale - 40 * scale);

return ["phone", "address", "slogan"];
